// 摆动控制变量
y = global.idealborder[2] - 130  // 基础Y坐标
xoff = 0  // X轴摆动偏移
yoff = 0  // Y轴摆动偏移
siner = 0  // 正弦计时器
headx = 0  // 头部X偏移（用于攻击动画）
heady = 0  // 头部Y偏移（用于攻击动画）

// 摆动模式选择（bounce = 0-3）
if (bounce == 3) {
    // 模式3：大幅垂直摆动（疲惫状态）
    siner += 1
    yoff = (sin(siner / 18)) * 2
    xoff = 0
}
if (bounce == 2) {
    // 模式2：中等幅度垂直摆动
    siner += 1
    yoff = (sin(siner / 15)) * 4
    xoff = 0
}
if (bounce == 1) {
    // 模式1：轻微8字形摆动（基础闲晃）
    siner += 1
    yoff = sin(siner / 3)  // 快速垂直摆动
    xoff = cos(siner / 6)  // 慢速水平摆动，形成8字形轨迹
}
if (bounce == 0) {
    // 模式0：静止
    siner = 0
    yoff = 0
    xoff = 0
}

